FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Colossians 2:17', 1),
  (1, 'Hebrews 8:5', 2),
  (4, 'Micah 6:6-8', 3),
  (4, 'Isaiah 1:11', 4),
  (5, 'Psalm 40:6-8', 5),
  (5, 'John 1:14', 6),
  (7, 'Luke 24:27', 7),
  (7, 'John 5:39', 8),
  (10, 'Hebrews 9:12', 9),
  (10, 'Hebrews 7:27', 10),
  (12, 'Hebrews 1:3', 11),
  (12, 'Psalm 110:1', 12),
  (14, 'Hebrews 9:28', 13),
  (17, 'Jeremiah 31:34', 14),
  (17, 'Hebrews 8:12', 15),
  (19, 'Hebrews 4:16', 16),
  (19, 'Ephesians 2:18', 17),
  (20, 'Matthew 27:51', 18),
  (20, 'John 14:6', 19),
  (22, 'Hebrews 9:14', 20),
  (22, 'Ezekiel 36:25', 21),
  (23, 'Hebrews 3:6', 22),
  (23, '1 Corinthians 1:9', 23),
  (25, 'Acts 2:42', 24),
  (25, 'Romans 13:11-12', 25),
  (26, 'Hebrews 6:4-6', 26),
  (26, 'Numbers 15:30-31', 27),
  (29, 'Hebrews 2:3-4', 28),
  (29, 'Matthew 12:31-32', 29),
  (30, 'Deuteronomy 32:35-36', 30),
  (31, 'Hebrews 12:29', 31),
  (34, 'Matthew 6:19-20', 32),
  (34, '1 Peter 1:4', 33),
  (37, 'Habakkuk 2:3-4', 34),
  (37, 'James 5:7-8', 35),
  (38, 'Romans 1:17', 36),
  (38, 'Galatians 3:11', 37),
  (39, 'Hebrews 6:9', 38),
  (39, '1 Peter 1:9', 39)
) AS cr(verse_number, reference, ref_order)
WHERE b.name = 'Hebrews' AND c.chapter_number = 10
  AND v.verse_number = cr.verse_number;
